command:
// ============================================================
// MACRO: Eliminar Esferas de Jugadores — Cosmere RPG
// Foundry VTT · Sistema cosmere-rpg
// ============================================================

const DENOMINACIONES = [
  { currency: "spheres", denom: "broam", label: "Broam (esferas)",   color: "#1a6fa8", valor: 50 },
  { currency: "spheres", denom: "mark",  label: "Mark (esferas)",    color: "#1a6fa8", valor: 5  },
  { currency: "spheres", denom: "chip",  label: "Chip (esferas)",    color: "#1a6fa8", valor: 1  },
  { currency: "dun",     denom: "broam", label: "Broam (apagadas)",  color: "#666666", valor: 50 },
  { currency: "dun",     denom: "mark",  label: "Mark (apagadas)",   color: "#666666", valor: 5  },
  { currency: "dun",     denom: "chip",  label: "Chip (apagadas)",   color: "#666666", valor: 1  },
];

function getPlayerActors() {
  return game.actors.filter(a => a.hasPlayerOwner && a.type === "character");
}

// Devuelve cuánto tiene un actor de una denominación concreta
function getActorStock(actor, currency, denom) {
  const item = actor.items.find(i =>
    i.type === "loot" &&
    i.system?.isMoney === true &&
    i.system?.price?.currency === currency &&
    i.system?.price?.denomination?.primary === denom
  );
  return item ? (item.system.quantity || 0) : 0;
}

function buildHTML(actors) {
  const actorRows = actors.map(a => `
    <label class="cr-actor">
      <input type="checkbox" class="actor-check" data-id="${a.id}" checked>
      <img src="${a.img}" alt="${a.name}">
      <span>${a.name}</span>
    </label>
  `).join("");

  const inputs = DENOMINACIONES.map(d => `
    <div class="cr-denom-row">
      <span class="cr-dot" style="background:${d.color}"></span>
      <span class="cr-denom-label">${d.label}</span>
      <input type="number" id="inp-${d.currency}-${d.denom}" class="cr-input" value="0" min="0">
    </div>
  `).join("");

  return `
    <style>
      #cr-wrap {
        font-family: "Signika", serif;
        color: #1a1a1a;
        font-size: 13px;
      }
      .cr-section { margin-bottom: 12px; }
      .cr-section h3 {
        margin: 0 0 7px;
        font-size: 11px;
        text-transform: uppercase;
        letter-spacing: 1.5px;
        color: #8a1a1a;
        border-bottom: 1px solid #d8b0b0;
        padding-bottom: 3px;
        font-weight: bold;
      }
      .cr-actors { display: flex; flex-wrap: wrap; gap: 6px; }
      .cr-actor {
        display: flex; flex-direction: column; align-items: center;
        cursor: pointer; padding: 5px 7px; border-radius: 5px;
        border: 1px solid #cca8a8; background: rgba(168,26,26,0.05);
        min-width: 58px; text-align: center;
        transition: border-color 0.15s, background 0.15s;
      }
      .cr-actor:hover { border-color: #a81a1a; background: rgba(168,26,26,0.10); }
      .cr-actor input[type=checkbox] { accent-color: #a81a1a; margin-bottom: 3px; }
      .cr-actor img {
        width: 40px; height: 40px; border-radius: 50%;
        object-fit: cover; border: 2px solid #cc8a8a; margin-bottom: 3px;
      }
      .cr-actor span { font-size: 10px; color: #1a1a1a; max-width: 62px; word-break: break-word; line-height: 1.2; }
      .cr-denom-row { display: flex; align-items: center; gap: 8px; margin-bottom: 6px; }
      .cr-dot { width: 10px; height: 10px; border-radius: 50%; flex-shrink: 0; border: 1px solid rgba(0,0,0,0.2); }
      .cr-denom-label { flex: 1; color: #1a1a1a; font-size: 13px; }
      .cr-input {
        width: 72px;
        background: #ffffff;
        border: 1px solid #bd8a8a;
        color: #1a1a1a;
        border-radius: 4px;
        padding: 3px 7px;
        font-size: 13px;
        text-align: right;
        box-shadow: inset 0 1px 2px rgba(0,0,0,0.08);
      }
      .cr-input:focus { outline: none; border-color: #a81a1a; box-shadow: 0 0 0 2px rgba(168,26,26,0.15); }
      .cr-opt {
        display: flex; align-items: center; gap: 7px;
        margin-bottom: 6px; font-size: 13px; cursor: pointer; color: #1a1a1a;
      }
      .cr-opt input[type=checkbox] { accent-color: #a81a1a; width: 15px; height: 15px; }
      #cr-preview {
        background: #f7f0f0;
        border: 1px solid #d8b0b0;
        border-radius: 5px;
        padding: 8px 10px;
        font-size: 12px;
        color: #2a2a2a;
        min-height: 32px;
        line-height: 1.6;
      }
      #cr-preview strong { color: #8a1a1a; }
      #cr-preview em { color: #666; font-style: normal; }
      .cr-warn { color: #c0392b; font-weight: bold; }
      .cr-ok { color: #1a6a1a; }
    </style>

    <div id="cr-wrap">
      <div class="cr-section">
        <h3>🔮 Jugadores</h3>
        <div class="cr-actors">${actorRows}</div>
      </div>
      <div class="cr-section">
        <h3>💸 Esferas a eliminar</h3>
        ${inputs}
      </div>
      <div class="cr-section">
        <h3>⚙️ Opciones</h3>
        <label class="cr-opt">
          <input type="checkbox" id="opt-chat" checked>
          Publicar en el chat
        </label>
      </div>
      <div class="cr-section">
        <h3>📋 Resumen</h3>
        <div id="cr-preview">Introduce cantidades para ver el resumen.</div>
      </div>
    </div>
  `;
}

function setupPreview(actors) {
  const refresh = () => {
    const checked = [...document.querySelectorAll(".actor-check:checked")];
    const n = checked.length;
    const nombres = checked.map(c => c.closest("label")?.querySelector("span")?.textContent ?? "?");
    const ids = checked.map(c => c.dataset.id);
    const seleccionados = actors.filter(a => ids.includes(a.id));

    const lineas = [];
    let hayProblemas = false;

    for (const d of DENOMINACIONES) {
      const val = parseInt(document.getElementById(`inp-${d.currency}-${d.denom}`)?.value) || 0;
      if (!val) continue;

      // Comprobar si algún actor no tiene suficiente
      const problemasActores = seleccionados
        .map(a => ({ name: a.name, tiene: getActorStock(a, d.currency, d.denom) }))
        .filter(x => x.tiene < val);

      if (problemasActores.length > 0) {
        hayProblemas = true;
        const lista = problemasActores.map(x => `${x.name} (tiene ${x.tiene})`).join(", ");
        lineas.push(`<span class="cr-warn">⚠️ ${val} ${d.label}: sin fondos suficientes → ${lista}</span>`);
      } else {
        lineas.push(`<strong>${val}</strong> ${d.label} eliminados a cada jugador`);
      }
    }

    const box = document.getElementById("cr-preview");
    if (!box) return;
    if (!n) { box.innerHTML = '<span class="cr-warn">⚠️ Selecciona al menos un jugador.</span>'; return; }
    if (!lineas.length) { box.innerHTML = "Introduce cantidades para ver el resumen."; return; }
    box.innerHTML = lineas.join("<br>") + `<br><em>→ ${nombres.join(", ")}</em>`;
  };

  document.querySelectorAll(".cr-input, .actor-check").forEach(el => {
    el.addEventListener("input", refresh);
    el.addEventListener("change", refresh);
  });
  refresh();
}

// Elimina monedas de un actor. Devuelve objeto con lo que realmente se quitó y si hubo déficit.
async function removeCoinsFromActor(actor, coins) {
  const resultado = { actor, quitado: {}, deficit: {} };

  for (const [key, cantidad] of Object.entries(coins)) {
    if (!cantidad) continue;
    const [currency, denom] = key.split("|");

    const item = actor.items.find(i =>
      i.type === "loot" &&
      i.system?.isMoney === true &&
      i.system?.price?.currency === currency &&
      i.system?.price?.denomination?.primary === denom
    );

    const disponible = item ? (item.system.quantity || 0) : 0;

    if (!item || disponible === 0) {
      // No tiene nada de esta denominación
      resultado.deficit[key] = cantidad;
      resultado.quitado[key] = 0;
    } else if (disponible >= cantidad) {
      // Tiene suficiente
      const nuevaCantidad = disponible - cantidad;
      if (nuevaCantidad === 0) {
        await item.delete();
      } else {
        await item.update({ "system.quantity": nuevaCantidad });
      }
      resultado.quitado[key] = cantidad;
    } else {
      // Tiene algo pero no suficiente — quita lo que pueda
      await item.delete();
      resultado.quitado[key] = disponible;
      resultado.deficit[key] = cantidad - disponible;
    }
  }

  return resultado;
}

function buildChatMsg(resultados) {
  const filas = resultados.map(({ actor, quitado, deficit }) => {
    const itemsQuitados = Object.entries(quitado)
      .filter(([, v]) => v > 0)
      .map(([k, v]) => {
        const [currency, denom] = k.split("|");
        const info = DENOMINACIONES.find(d => d.currency === currency && d.denom === denom);
        return `${v} ${info?.label ?? k}`;
      }).join(", ");

    const itemsDeficit = Object.entries(deficit)
      .filter(([, v]) => v > 0)
      .map(([k, v]) => {
        const [currency, denom] = k.split("|");
        const info = DENOMINACIONES.find(d => d.currency === currency && d.denom === denom);
        return `<span style="color:#c0392b">${v} ${info?.label ?? k} (sin fondos)</span>`;
      }).join(", ");

    const partes = [];
    if (itemsQuitados) partes.push(itemsQuitados);
    if (itemsDeficit) partes.push(itemsDeficit);

    return `<li><strong>${actor.name}</strong>: ${partes.join(" · ") || "—"}</li>`;
  }).join("");

  return `
    <div style="border:1px solid #d8a8a8;border-radius:6px;padding:10px;background:rgba(168,26,26,0.04);">
      <h3 style="color:#8a1a1a;margin:0 0 6px;font-size:14px;">💸 Eliminación de Esferas</h3>
      <ul style="margin:0;padding-left:16px;font-size:12px;color:#1a1a1a;">${filas}</ul>
    </div>
  `;
}

// ── MAIN ─────────────────────────────────────────────────────
const actores = getPlayerActors();

if (!actores.length) {
  ui.notifications.warn("No se encontraron personajes de jugadores.");
} else {
  new Dialog({
    title: "Eliminar Esferas · Cosmere RPG",
    content: buildHTML(actores),
    buttons: {
      ok: {
        icon: '<i class="fas fa-minus-circle"></i>',
        label: "Eliminar",
        callback: async (html) => {
          const ids = [...html.find(".actor-check:checked")].map(el => el.dataset.id);
          const seleccionados = actores.filter(a => ids.includes(a.id));
          if (!seleccionados.length) { ui.notifications.warn("No hay jugadores seleccionados."); return; }

          const chat = html.find("#opt-chat").is(":checked");

          const totales = {};
          for (const d of DENOMINACIONES) {
            const v = parseInt(html.find(`#inp-${d.currency}-${d.denom}`).val()) || 0;
            totales[`${d.currency}|${d.denom}`] = v;
          }

          const resultados = [];
          for (const actor of seleccionados) {
            const r = await removeCoinsFromActor(actor, totales);
            resultados.push(r);
          }

          // Notificar déficits
          const conDeficit = resultados.filter(r => Object.values(r.deficit).some(v => v > 0));
          if (conDeficit.length) {
            const nombres = conDeficit.map(r => r.actor.name).join(", ");
            ui.notifications.warn(`⚠️ Fondos insuficientes para: ${nombres}. Se quitó lo disponible.`);
          }

          if (chat) {
            await ChatMessage.create({
              content: buildChatMsg(resultados),
              speaker: ChatMessage.getSpeaker({ alias: "GM" }),
            });
          }

          ui.notifications.info(`✅ Esferas eliminadas de ${seleccionados.length} jugador(es).`);
        }
      },
      cancelar: { icon: '<i class="fas fa-times"></i>', label: "Cancelar" }
    },
    default: "ok",
    render: () => setupPreview(actores),
    width: 440,
  }).render(true);
}
